firmware_template.source:
#include "web_server.h"
#include <WiFi.h>
#include <ESPAsyncWebServer.h>
static AsyncWebServer* _srv=nullptr;
void webserver_setup(uint16_t port){_srv=new AsyncWebServer(port);_srv->begin();Serial.printf("[web] OK port=%d\n",port);}
void webserver_on(const char*p,const char*r){if(!_srv)return;String resp=String(r);_srv->on(p,HTTP_GET,[resp](AsyncWebServerRequest*req){req->send(200,"text/html",resp);});}
void webserver_on_post(const char*p,void(*h)(const char*)){if(!_srv)return;_srv->on(p,HTTP_POST,[h](AsyncWebServerRequest*req){if(req->hasParam("body",true))h(req->getParam("body",true)->value().c_str());req->send(200);});}
